}

.login-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    padding: 1rem;
    background: transparent;
    border: 2px solid #00ff99;
    color: #00ff99;
    font-size: 1.1rem;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.3s ease;
    font-family: 'Courier New', monospace;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.login-btn:hover {
    background: rgba(0, 255, 153, 0.1);
    box-shadow: 0 0 20px rgba(0, 255, 153, 0.3);
}

.divider {
    display: flex;
    align-items: center;
    text-align: center;
    margin: 1.5rem 0;
    color: #00ff99;
}

.divider::before,
.divider::after {
    content: '';
    flex: 1;
    border-bottom: 1px solid #00ff99;
}

.divider span {
    padding: 0 1rem;
    font-size: 0.9rem;
    text-transform: uppercase;
}

.google-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1rem;
    width: 100%;
    padding: 1rem;
    background: transparent;
    border: 2px solid #00ff99;
    color: #00ff99;
    font-size: 1.1rem;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.3s ease;
    font-family: 'Courier New', monospace;
}

.google-btn:hover {
    background: rgba(0, 255, 153, 0.1);
    box-shadow: 0 0 20px rgba(0, 255, 153, 0.3);
}

.google-icon {
    width: 20px;
    height: 20px;
}

.signup-link {
    margin-top: 1.5rem;
    color: #00ff99;
    font-size: 0.9rem;
}

.signup-link a {
    color: #00ff99;
    text-decoration: none;
    font-weight: bold;
    transition: all 0.3s ease;
}

.signup-link a:hover {
    text-shadow: 0 0 10px #00ff99;
}

.glow-line {
    position: absolute;
    left: 0;
    width: 100%;
    height: 2px;
    background: linear-gradient(90deg, transparent, #00ff99, transparent);
    animation: glow 2s linear infinite;
}

.glow-line.top {
    top: 0;
}

.glow-line.bottom {
    bottom: 0;
}

@keyframes glow {
    0% {
        transform: translateX(-100%);
    }
    100% {
        transform: translateX(100%);
    }
}

html, body {
    height: 100%;
    margin: 0;
    padding: 0;
    background: linear-gradient(135deg, #050d05 0%, #001a0a 100%);
    box-sizing: border-box;
}

#main {
    min-height: 100vh;
    width: 100vw;
    background: transparent;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

.assessment-container {
    padding: 1rem;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 70vh;
    background: linear-gradient(135deg, rgba(0, 0, 0, 0.95) 0%, rgba(0, 20, 0, 0.95) 100%);
    position: relative;
}

.timer {
    position: absolute;
    left: 2rem;
    top: 2rem;
    color: #00ff99;
    font-size: 1.5rem;
    font-family: 'Courier New', monospace;
    text-shadow: 0 0 10px rgba(0, 255, 0, 0.3);
}

.assessment-content {
    display: none;
}

.exit-btn {
    position: absolute;
    top: 1rem;
    right: 1rem;
    background: transparent;
    border: none;
    color: #00ff99;
    font-size: 1.5rem;
    cursor: pointer;
    width: 30px;
    height: 30px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    transition: all 0.3s ease;
    z-index: 10;
}

.exit-btn:hover {
    background: rgba(0, 255, 0, 0.1);
    box-shadow: 0 0 15px rgba(0, 255, 0, 0.3);
}

.title {
    color: #00ff99;
    font-size: clamp(1.8rem, 5vw, 2.5rem);
    margin-bottom: 1rem;
    font-family: 'Arial', sans-serif;
    text-transform: uppercase;
    letter-spacing: 2px;
    line-height: 1.3;
    text-shadow: 0 0 10px rgba(0, 255, 0, 0.3);
    padding: 0 1rem;
    word-wrap: break-word;
}

.description {
    color: rgba(255, 255, 255, 0.8);
    font-size: clamp(1rem, 3vw, 1.1rem);
    margin-bottom: 2rem;
    line-height: 1.5;
}

.digital-input-wrapper {
    position: relative;
    width: 100%;
    max-width: 400px;
    margin: 0 auto 2rem;
}

.digital-input {
    width: 100%;
    padding: 1rem;
    font-size: 1.2rem;
    background: rgba(0, 0, 0, 0.8);
    border: 2px solid #00ff99;
    color: #00ff99;
    border-radius: 4px;
    outline: none;
    font-family: 'Courier New', monospace;
    transition: all 0.3s ease;
    text-align: center;
    letter-spacing: 2px;
}

.digital-input::placeholder {
    color: rgba(0, 255, 0, 0.5);
}

.digital-input:focus {
    box-shadow: 0 0 15px rgba(0, 255, 0, 0.5);
}

.glow-line {
    position: absolute;
    left: 0;
    width: 100%;
    height: 2px;
    background: linear-gradient(90deg, transparent, #00ff99, transparent);
    animation: glow 2s linear infinite;
}

.glow-line.top {
    top: 0;
}

.glow-line.bottom {
    bottom: 0;
    animation: glow-reverse 2s linear infinite;
}

.submit-btn {
    background: transparent;
    border: 2px solid #00ff99;
    color: #00ff99;
    padding: 1rem 2rem;
    font-size: 1.1rem;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.3s ease;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: bold;
}

.submit-btn:hover {
    background: rgba(0, 255, 0, 0.1);
    box-shadow: 0 0 20px rgba(0, 255, 0, 0.3);
}

@keyframes glow {
    0% {
        transform: translateX(-100%);
    }
    100% {
        transform: translateX(100%);
    }
}

@keyframes glow-reverse {
    0% {
        transform: translateX(100%);
    }
    100% {
        transform: translateX(-100%);
    }
}

/* Layout for two main sections */
.main-sections {
    display: flex;
    justify-content: center;
    align-items: stretch;
    gap: 2rem;
    padding: 3rem 1rem;
    flex-wrap: wrap;
}

/* Main section containers */
.kbase-section, .assessment-section {
    background: linear-gradient(135deg, rgba(0, 0, 0, 0.95) 0%, rgba(0, 20, 0, 0.95) 100%);
    border-radius: 12px;
    box-shadow: 0 0 30px rgba(0, 255, 0, 0.15);
    padding: 2.5rem 2rem;
    min-width: 320px;
    max-width: 400px;
    flex: 1 1 320px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    position: relative;
    margin-bottom: 2rem;
}

/* .section-content is used for both sections */
.section-content {
    width: 100%;
    text-align: center;
    position: relative;
}

.section-title {
    color: #00ff99;
    font-size: 2.2rem;
    margin-bottom: 1rem;
    font-family: 'Arial', sans-serif;
    text-transform: uppercase;
    letter-spacing: 2px;
    text-shadow: 0 0 10px rgba(0, 255, 0, 0.3);
}

.section-description {
    color: rgba(255, 255, 255, 0.85);
    font-size: 1.1rem;
    margin-bottom: 2.5rem;
    line-height: 1.5;
}

.explore-btn {
    background: transparent;
    border: 2px solid #00ff99;
    color: #00ff99;
    padding: 1rem 2.5rem;
    font-size: 1.1rem;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.3s ease;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: bold;
    box-shadow: 0 0 20px rgba(0, 255, 0, 0.15);
}

.explore-btn:hover {
    background: rgba(0, 255, 0, 0.08);
    box-shadow: 0 0 30px rgba(0, 255, 0, 0.3);
}

/* Responsive remains the same */
@media (max-width: 900px) {
    .main-sections {
        flex-direction: column;
        align-items: center;
        gap: 2.5rem;
    }
    .kbase-section, .assessment-section {
        max-width: 95vw;
        min-width: 0;
    }
}
